commands.cmd:
meminfo=$(cat /proc/meminfo) || { echo "meminfo unreadable" >&2; exit 1; }
swappiness=$(cat /proc/sys/vm/swappiness) || { echo "swappiness unreadable" >&2; exit 1; }
printf '%s\n' "$meminfo" | awk -v sw="$swappiness" '
  /^SwapTotal:/{t=$2}
  /^SwapFree:/{f=$2}
  END{
    printf "{\"swap_total_kb\":%d,\"swap_free_kb\":%d,\"swappiness\":%d,\"swap_used_pct\":\"%.1f\"}",
      t, f, sw, (t>0 ? (t-f)/t*100 : 0)
  }' || exit 1
